return [{ json: {
  run_id:          'log_analyse_' + new Date().toISOString().replace(/[^0-9]/g,'').slice(0,14),
  run_date:        new Date().toISOString(),
  log_since_days:  7,
  // LXC-Namen die ausgeschlossen werden (n8n selbst + Claude Code API)
  exclude_names:   ['n8n', 'claude'],
  tickets_created: 0
} }];

const data = $input.first().json;
const systems = data.systems || [];
const active  = systems.filter(s => s.ip);
if (active.length === 0) {
  // Dummy-Item damit Loop sofort fertig ist
  return [{ json: { _skip: true, name: '__no_devices__', ip: null } }];
}
return active.map(s => ({ json: s }));

const sys    = $input.first().json;
const config = $('📋 Set Config').first().json;

if (sys._skip) return [{ json: { _skip: true, system_name: sys.name } }];

const ssh_user   = sys.ssh_user   || 'root';
const ssh_pass   = sys.ssh_password || '';
const ssh_prefix = ssh_pass
  ? `sshpass -p '${ssh_pass}' ssh -o StrictHostKeyChecking=no -o ConnectTimeout=10 -o BatchMode=no ${ssh_user}@${sys.ip}`
  : `ssh -o StrictHostKeyChecking=no -o ConnectTimeout=10 ${ssh_user}@${sys.ip}`;

const isDevice = sys.type === 'device';

// === RouterOS / Network Devices ===
const device_cmds = [
  `/log print`,
  `/system health print`,
  `/interface print stats`,
  `/system resource print`,
  `/ip firewall filter print where action=drop`,
  `/log print where topics~"error" or topics~"critical" or topics~"warning"`,
].join('\n');

// === Linux Devices: System- UND Application-Logs ===
const linux_cmds = [
  // --- System Logs ---
  `echo "=== JOURNALCTL SYSTEM (${config.log_since_days}d, prio>=warning) ==="`,
  `journalctl --no-pager -p warning --since '${config.log_since_days} days ago' 2>/dev/null | tail -500`,
  `echo "=== JOURNALCTL BOOT (prio>=warning) ==="`,
  `journalctl -b --no-pager -p warning 2>/dev/null | tail -300`,
  `echo "=== DMESG (warn/err/crit) ==="`,
  `dmesg --level=warn,err,crit 2>/dev/null | tail -200`,
  `for log in /var/log/syslog /var/log/messages /var/log/kern.log /var/log/auth.log; do [ -f "$log" ] && echo "=== $log ===" && grep -iE 'warn|error|crit|fail|fatal' "$log" 2>/dev/null | tail -100; done`,
  // --- Failed/Degraded Services ---
  `echo "=== FAILED/DEGRADED SERVICES ==="`,
  `systemctl list-units --state=failed,degraded --no-legend 2>/dev/null`,
  // --- Service-spezifische Logs (alle aktiven Services mit Warnings) ---
  `echo "=== SERVICE WARNINGS (${config.log_since_days}d) ==="`,
  `for svc in $(systemctl list-units --type=service --state=active --no-legend 2>/dev/null | awk '{print $1}' | grep -v '@' | head -40); do out=$(journalctl -u $svc --no-pager -p warning --since '${config.log_since_days} days ago' 2>/dev/null | tail -15); [ -n "$out" ] && echo "--- SERVICE: $svc ---" && echo "$out"; done`,
  // --- Application Logs: nginx ---
  `[ -d /var/log/nginx ] && echo "=== APP: nginx ===" && find /var/log/nginx -name '*.log' 2>/dev/null | xargs -I{} sh -c 'cnt=$(grep -ciE "warn|error|crit|emerg" "{}" 2>/dev/null); [ "$cnt" -gt 0 ] && echo "--- {} ($cnt) ---" && grep -iE "warn|error|crit|emerg" "{}" 2>/dev/null | tail -50' || true`,
  // --- Application Logs: Apache2 ---
  `[ -d /var/log/apache2 ] && echo "=== APP: apache2 ===" && find /var/log/apache2 -name '*.log' 2>/dev/null | xargs -I{} sh -c 'cnt=$(grep -ciE "warn|error|crit|emerg" "{}" 2>/dev/null); [ "$cnt" -gt 0 ] && echo "--- {} ($cnt) ---" && grep -iE "warn|error|crit|emerg" "{}" 2>/dev/null | tail -50' || true`,
  // --- Application Logs: MySQL/MariaDB ---
  `for log in /var/log/mysql/error.log /var/log/mariadb/mariadb.log /var/log/mysql.err; do [ -f "$log" ] && echo "=== APP: MySQL/MariaDB ($log) ===" && grep -iE 'warn|error|fail' "$log" 2>/dev/null | tail -50; done`,
  // --- Application Logs: PostgreSQL ---
  `[ -d /var/log/postgresql ] && echo "=== APP: PostgreSQL ===" && find /var/log/postgresql -name '*.log' 2>/dev/null | xargs -I{} sh -c 'grep -iE "warn|error|fatal|panic" "{}" 2>/dev/null | tail -50' || true`,
  // --- Application Logs: Redis ---
  `for log in /var/log/redis/redis-server.log /var/log/redis.log; do [ -f "$log" ] && echo "=== APP: Redis ===" && grep -iE 'warn|error|fail|critical' "$log" 2>/dev/null | tail -30; done`,
  // --- Generic App Log Scan: /var/log (alle .log außer Standardlogs) ---
  `echo "=== APP LOGS SCAN (/var/log) ==="`,
  `find /var/log -maxdepth 3 -name '*.log' -not -empty 2>/dev/null | grep -vE '/(syslog|messages|kern\\.log|auth\\.log|dpkg\\.log|apt/|btmp|wtmp|lastlog|faillog|journal)' | head -30 | xargs -I{} sh -c 'cnt=$(grep -ciE "warn|error|crit|fail|fatal|exception" "{}" 2>/dev/null); [ "$cnt" -gt 0 ] && echo "--- {} ($cnt hits) ---" && grep -iE "warn|error|crit|fail|fatal|exception" "{}" 2>/dev/null | tail -30'`,
  // --- Generic App Log Scan: /opt ---
  `echo "=== APP LOGS SCAN (/opt) ==="`,
  `find /opt -maxdepth 4 -name '*.log' -not -empty 2>/dev/null | head -20 | xargs -I{} sh -c 'cnt=$(grep -ciE "warn|error|crit|fail|fatal|exception|traceback" "{}" 2>/dev/null); [ "$cnt" -gt 0 ] && echo "--- {} ($cnt hits) ---" && grep -iE "warn|error|crit|fail|fatal|exception|traceback" "{}" 2>/dev/null | tail -30'`,
].join('\n');

const cmds = isDevice ? device_cmds : linux_cmds;

const prompt = `Du bist ein erfahrener Systemadministrator. Analysiere ALLE Logquellen des folgenden Systems vollständig.

=== SYSTEM ===
Name: ${sys.name}
IP: ${sys.ip}
Typ: ${sys.type}
SSH: ${ssh_prefix}

=== AUFGABE ===
1. Verbinde dich per SSH mit dem System
2. Führe folgende Befehle zur Log-Sammlung aus:

${cmds}

3. Analysiere ALLE gesammelten Ausgaben auf Probleme – egal ob System-Logs, Application-Logs oder Service-Logs
4. Berücksichtige JEDE Warnung und jeden Fehler, unabhängig von der Quelle
5. Gruppiere ähnliche Fehler desselben Service/Komponente
6. KEINE Behebungsmaßnahmen – nur Analyse und Dokumentation!

=== ANTWORTFORMAT (NUR JSON, kein Markdown, kein erklärender Text) ===
{
  "hostname": "${sys.name}",
  "ip": "${sys.ip}",
  "type": "${sys.type}",
  "ssh_success": true,
  "has_findings": false,
  "findings": [
    {
      "severity": "WARNING|ERROR|CRITICAL",
      "source": "system|application|service",
      "component": "z.B. kernel, systemd, nginx, postgresql, sshd",
      "summary": "Einzeilige Beschreibung des Problems",
      "details": "Relevante Log-Zeilen (max. 5 Zeilen)",
      "count": 1,
      "first_seen": "2026-03-23T01:00:00Z"
    }
  ],
  "error": null
}

WICHTIG:
- Antworte NUR mit dem JSON-Objekt
- Wenn SSH fehlschlägt: ssh_success=false, has_findings=false, error=<Fehlermeldung>
- Ignoriere rein informative Meldungen (INFO/DEBUG/NOTICE)
- source="system" für Kernel/dmesg/journalctl-System-Einträge
- source="application" für App-spezifische Logfiles (nginx, postgresql, mysql etc.)
- source="service" für systemd-Unit-Logs (journalctl -u <service>)
- Alle Schweregrade WARNING und höher erfassen – egal welche Quelle`;

return [{ json: {
  system_name: sys.name,
  system_ip:   sys.ip,
  system_type: sys.type,
  prompt
} }];

const inp    = $('🔧 P1: Build Device Prompt').first().json;
const claude = $input.first().json;

// Skip-Dummy durchreichen
if (inp._skip) return [{ json: { _skip: true, has_findings: false } }];

let data = { ssh_success: false, has_findings: false, findings: [], error: 'Keine Antwort' };
try {
  const text    = claude.response_text || '';
  const cleaned = text.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
  const match   = cleaned.match(/\{[\s\S]*\}/);
  if (match) data = { ...data, ...JSON.parse(match[0]) };
} catch(e) {
  data.error = 'JSON Parse-Fehler: ' + e.message;
}

const findings = (data.findings || []).filter(f =>
  ['WARNING','ERROR','CRITICAL'].includes((f.severity||'').toUpperCase())
);

return [{ json: {
  system_name:    inp.system_name,
  system_ip:      inp.system_ip,
  system_type:    inp.system_type,
  ssh_success:    data.ssh_success,
  has_findings:   data.ssh_success && findings.length > 0,
  findings_count: findings.length,
  findings,
  error:          data.error
} }];

