body += `**Analyse:** ${new Date().toISOString().slice(0,19).replace('T',' ')} UTC\n`;
body += `**Run-ID:** ${config.run_id}\n\n`;

// Quellen-Übersicht
body += `### Befunde nach Quelle\n`;
