  const icon = src_icon[src] || '📋';
  body += `- ${icon} **${src}**: ${items.length} Befund(e)\n`;
}
body += `\n---\n\n`;

// Detaillierte Befunde
body += `## Befunde (${inp.findings_count})\n\n`;
