  body += `### ${icon} ${f.severity}: ${f.summary}\n`;
  body += `- **Komponente:** ${f.component}\n`;
  body += `- **Quelle:** ${srcIcon} ${f.source || 'system'}\n`;
  body += `- **Anzahl:** ${f.count || 1}\n`;
  if (f.first_seen) body += `- **Erstes Auftreten:** ${f.first_seen}\n`;
  body += `\n**Log-Auszug:**\n\`\`\`\n${f.details}\n\`\`\`\n\n`;
}
body += `---\n*Automatisch erstellt – keine Behebungsmaßnahmen erforderlich.*`;

const priority = max_sev === 'CRITICAL' ? '1 very high'
               : max_sev === 'ERROR'    ? '2 high'
               :                          '3 normal';

return [{ json: { title, body, queue: 'Raw', state: 'neu', priority } }];

